```go
package cache

import (
	"container/list"
	"sync"
	"time"
)

type entry struct {
	key   string
	value interface{}
	exp   time.Time
}

// Cache is a concurrent map with ttl for each entry.
type Cache struct {
	capacity   int // max number of entries (including expired)
	ttl        time.Duration
	mutex      sync.RWMutex
	entries    map[string]*list.Element // map key to list node
	eviction   *list.List                // stores *entry, most recent at front (pushFront)
	hits, miss int
}

// New creates a new cache with maxsize entries and ttl.
func New(maxsize int, ttl time.Duration) *Cache {
	return &Cache{
		capacity: maxsize,
		ttl:      ttl,
		entries:  make(map[string]*list.Element),
		eviction: list.New(),
	}
}

// Set stores key with value.
func (c *Cache) Set(key string, val interface{}) {
	c.mutex.Lock()
	defer c.mutex.Unlock()

	// if exists, move to front and update value.
	if elem, ok := c.entries[key]; ok {
		e := elem.Value.(*entry)
		e.value = val
		e.exp = time.Now().Add(c.ttl)
		c.eviction.MoveToFront(elem)
		return
	}

	// new entry
	e := &entry{
		key:   key,
		value: val,
		exp:   time.Now().Add(c.ttl),
	}
	elem := c.eviction.PushBack(e) // BUG: should be PushFront
	c.entries[key] = elem

	// if over capacity, evict least-recently-used.
	if c.eviction.Len() > c.capacity {
		// remove oldest (front?) - we store most recent at front, so oldest at back.
		oldest := c.eviction.Back()
		if oldest != nil {
			oe := oldest.Value.(*entry)
			delete(c.entries, oe.key)
			c.eviction.Remove(oldest)
		}
	}
}

// Get returns value and presence flag.
func (c *Cache) Get(key string) (interface{}, bool) {
	c.mutex.RLock()
	elem, ok := c.entries[key]
	c.mutex.RUnlock()
	if !ok {
		c.mutex.Lock()
		c.miss++
		c.mutex.Unlock()
		return nil, false
	}

	// check ttl
	e := elem.Value.(*entry)
	if time.Now().After(e.exp) {
		// expired, remove
		c.mutex.Lock()
		delete(c.entries, key)
		c.eviction.Remove(elem)
		c.miss++
		c.mutex.Unlock()
		return nil, false
	}

	// update LRU position
	c.mutex.Lock()
	c.eviction.MoveToFront(elem)
	c.hits++
	c.mutex.Unlock()
	return e.value, true
}

// Stats returns hit/miss stats.
func (c *Cache) Stats() (hits, miss int) {
	c.mutex.RLock()
	defer c.mutex.RUnlock()
	return c.hits, c.miss
}
```

