package cache

import (
	"testing"
	"time"
)

func TestSetAndGet(t *testing.T) {
	c := New(10, time.Second*10)
	c.Set("alpha", 1)
	c.Set("beta", 2)
	c.Set("gamma", 3)

	if v, ok := c.Get("alpha"); !ok || v.(int) != 1 {
		t.Errorf("Get(\"alpha\"): expected hit, got miss")
	}
	if v, ok := c.Get("beta"); !ok || v.(int) != 2 {
		t.Errorf("Get(\"beta\"): expected hit, got miss")
	}
	if v, ok := c.Get("gamma"); !ok || v.(int) != 3 {
		t.Errorf("Get(\"gamma\"): expected hit, got miss")
	}

	h, m := c.Stats()
	if h != 3 {
		t.Errorf("expected 3 hits, got %d", h)
	}
	if m != 0 {
		t.Errorf("expected 0 misses, got %d", m)
	}
}

// Test MaxSize Eviction
func TestMaxSizeEviction(t *testing.T) {
	c := New(5, time.Second*10)
	// Insert 10 items, older ones should be evicted.
	for i := 0; i < 10; i++ {
		key := fmt.Sprintf("key-%d", i)
		c.Set(key, i)
	}
	// The 5 most recent keys (5-9) should be present.
	for i := 5; i < 10; i++ {
		key := fmt.Sprintf("key-%d", i)
		if v, ok := c.Get(key); !ok || v.(int) != i {
			t.Errorf("Get(\"%s\"): expected hit for recent entry, got miss", key)
		}
	}
}

// Test TTL expiration
func TestTTLExpiration(t *testing.T) {
	c := New(10, time.Millisecond*10)
	c.Set("temp", 42)
	time.Sleep(time.Millisecond * 20)
	if _, ok := c.Get("temp"); ok {
		t.Fatalf("expected entry to be expired")
	}
}

// Test concurrent access
func TestConcurrent(t *testing.T) {
	c := New(100, time.Second*5)
	var wg sync.WaitGroup
	for i := 0; i < 1000; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			key := fmt.Sprintf("k-%d", i)
			c.Set(key, i)
			c.Get(key)
		}(i)
	}
	wg.Wait()
}
